SELECT AVG(marketvalue) AS average_market_value
FROM holdings
WHERE portfolio_id = 0;

SELECT SUM(marketvalue) AS total_market_value
FROM holdings
WHERE portfolio_id = 1;

SELECT portfolio_id, COUNT(*) AS total_holdings
FROM holdings
GROUP BY portfolio_id;

SELECT COUNT(*), SUM(total_amount)
FROM portfolio_transactions
WHERE transaction_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT portfolio_name
FROM portfolios
ORDER BY created_date DESC;

SELECT name, marketvalue
FROM holdings
ORDER BY marketvalue DESC;

SELECT AVG(portfolio_id) AS average_portfolio_id
FROM portfolios
WHERE status = 'active' AND risk_level = 'high';

SELECT status, COUNT(portfolio_id) AS number_of_portfolios
FROM portfolios
GROUP BY status;
